```

```csharp
int Add(int a, int b)          { return a + b; }
double Add(double a, double b) { return a + b; }

Add(2, 3);     // uses int version
Add(2.5, 3.5); // uses double version
```

```csharp
class MathHelper
{
    public static int Square(int n)
    {
        return n * n;
    }
}

Console.WriteLine(MathHelper.Square(4)); // no 'new' needed
```

```csharp
void PrintPositive(int n)
{
    if (n <= 0) return; // exit early
    Console.WriteLine(n);
}

PrintPositive(-1); // prints nothing
PrintPositive(5);  // prints 5
```
